3	type CellKey = string;
4	
5	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
6	  [-1, -1], [-1, 0], [-1, 1],
7	  [ 0, -1],          [ 0, 1],
8	  [ 1, -1], [ 1, 0], [ 1, 1],
9	];
10	
11	const keyOf = ([x, y]: Cell): CellKey => `${x},${y}`;
12	
13	const cellOf = (key: CellKey): Cell => {
14	  const [x, y] = key.split(",");
15	  return [Number(x), Number(y)];
16	};
17	
18	const survives = (wasAlive: boolean, liveNeighbors: number): boolean =>
19	  liveNeighbors === 3 || (wasAlive && liveNeighbors === 2);
20	
21	const countLiveNeighbors = (cells: Cell[]): Map<CellKey, number> => {
22	  const counts = new Map<CellKey, number>();
23	  for (const [x, y] of cells) {
24	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
25	      const neighbor = keyOf([x + dx, y + dy]);
26	      counts.set(neighbor, (counts.get(neighbor) ?? 0) + 1);
27	    }
28	  }
29	  return counts;
30	};
31	
32	export function nextGeneration(cells: Cell[]): Cell[] {
33	  const liveCells = new Set(cells.map(keyOf));
34	  const neighborCounts = countLiveNeighbors(cells);
35	
36	  const survivors: Cell[] = [];
37	  for (const [key, count] of neighborCounts) {
38	    if (survives(liveCells.has(key), count)) {
39	      survivors.push(cellOf(key));
40	    }
41	  }
42	  return survivors;
43	}
